const text = $input.item.json.message.text.trim();

// Format 1: "Hello. You spent AED 19.00 at CAREEM PLUS on your Credit Card  526039****7003 on 18/05. Combined Available Balance: AED 5893.14."
const format1 = /You spent AED\s*([\d,.]+)\s*at\s*(.+?)\s*on your Credit Card\s+([\d*Xx]+)\s+on\s*([\d/]+)\.\s*Combined Available Balance: AED\s*([\d,.]+)/i;

// Format 2: 
// "Credit Card Purchase Card Ending: 0947 At: LAVASH RESTAURANT EST, DUBAI Amount: AED 188.00 Date: 25/05/2025, 15:51 Available Limit: AED 5,752.86"
const format2 = /Card Ending:\s*(\d+)\s*At:\s*(.+?)\s*Amount:\s*AED\s*([\d,.]+)\s*Date:\s*([\d/]+),\s*(\d{2}:\d{2})\s*Available Limit:\s*AED\s*([\d,.]+)/i;

// Format 3: 
// "Payment for ENOC SITE 1066 of AED 129.00 has been made using Credit Card ending with 0947. Available limit AED 5,347.87."
const format3 = /Payment for\s*(.+?)\s*of AED\s*([\d,.]+).+ending (?:with|in)\s*([\d*Xx]+).+Available limit AED\s*([\d,.]+)/i;

let match;
let out = {};

if (format1.test(text)) {
    match = text.match(format1);
    out = {
        "Amount": match[1],
        "Merchant": match[2],
        "Card Number": match[3],
        "Date": match[4],
        "Available Balance": match[5]
    };
} else if (format2.test(text)) {
    match = text.match(format2);
    out = {
        "Card Ending": match[1],
        "Merchant": match[2],
        "Amount": match[3],
        "Date": match[4],
        "Time": match[5],
        "Available Limit": match[6]
    };
} else if (format3.test(text)) {
    match = text.match(format3);
    out = {
        "Merchant": match[1],
        "Amount": match[2],
        "Card Ending": match[3],
        "Available Limit": match[4]
    };
} else {
    out = { error: "No known transaction format matched.", text };
}

return [{ json: out }];
